Javascript.validate:
		
			//Date picker: error message “The value does not conform to a valid date format of DD-MMM-YYYY”.
			//Validation: Date cannot be in the past
            
			//Date to be not less than 14 days from date of filing of report
        	//under Rule 5.13 nor more than 28 days from date of consideration of 
        	//report under Rule 5.12.  Pres return to continue.
        	var checkDate = Services.getValue(InterimExtendDate.dataBinding); 
			var err = null;
			if( false == isFutureDate(checkDate))
			{ 	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg");
			}				
			return err;
